import Foundation

struct CategoryContent3 {
    static let generativeAI = CategoryData(
        id: "generative_ai", name: "AI That Creates", icon: "sparkles", colorName: "aiPink",
        description: "How AI makes text, images, and more from scratch",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 2,
        unlockRequirement: .completeCategory("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "ga_l1", title: "What is Generative AI?", description: "AI that creates new content", categoryId: "generative_ai", questions: [
        Question(id: "ga1_q1", type: .multipleChoice, questionText: "Generative AI is AI that:", options: ["Creates new content like text, images, or code", "Only classifies existing data into categories", "Optimizes search engine results", "Detects anomalies in datasets"], correctAnswer: "Creates new content like text, images, or code", explanation: "Generative AI produces new content — text, images, music, code — that did not exist before, powering tools from Anthropic, OpenAI, Google, Stability AI, and many others."),
        Question(id: "ga1_q2", type: .trueFalse, questionText: "Claude, GPT, Gemini, and Llama are all examples of generative AI.", options: ["True", "False"], correctAnswer: "True", explanation: "All of these models generate new text responses. Claude is made by Anthropic, GPT by OpenAI, Gemini by Google DeepMind, and Llama by Meta AI — each representing a different approach to generative AI."),
        Question(id: "ga1_q3", type: .fillInBlank, questionText: "A __________ is a type of AI that generates new content like text, images, or code.", options: ["generative model", "discriminative model", "classification model", "retrieval system"], correctAnswer: "generative model", explanation: "Generative models learn patterns from training data and use them to create new, similar content. They power chatbots, image generators, and code assistants across the industry."),
        Question(id: "ga1_q4", type: .multipleChoice, questionText: "Which is NOT an output of generative AI?", options: ["Physical objects from thin air", "Written essays and articles", "Generated images and artwork", "Computer code and scripts"], correctAnswer: "Physical objects from thin air", explanation: "Generative AI creates digital content — it cannot create physical objects without manufacturing equipment, though it can design objects for 3D printing."),
        Question(id: "ga1_q5", type: .matchPairs, questionText: "Match generative AI tools to what they create:", matchPairs: [
            MatchPair(term: "Claude / GPT", definition: "Text and conversations"),
            MatchPair(term: "Stable Diffusion", definition: "Images from descriptions"),
            MatchPair(term: "GitHub Copilot", definition: "Programming code"),
            MatchPair(term: "Suno / Udio", definition: "Music and songs")
        ], explanation: "The generative AI ecosystem spans text, images, code, and audio, with different companies specializing in different modalities."),
        Question(id: "ga1_q6", type: .scenarioJudgment, questionText: "A student submits an essay entirely written by generative AI without disclosure. Is this appropriate?", options: ["No, it's problematic", "Yes, it's fine", "It depends"], correctAnswer: "No, it's problematic", explanation: "Submitting AI-generated work as your own without disclosure is generally considered academic dishonesty, regardless of which model was used.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "ga_l2", title: "Large Language Models", description: "The brains behind AI chatbots", categoryId: "generative_ai", questions: [
        Question(id: "ga2_q1", type: .multipleChoice, questionText: "What does 'LLM' stand for?", options: ["Large Language Model", "Linear Learning Machine", "Layered Logic Module", "Language Linking Method"], correctAnswer: "Large Language Model", explanation: "LLM stands for Large Language Model — AI trained on vast amounts of text data. Examples include Claude, GPT, Gemini, Llama, and Mistral."),
        Question(id: "ga2_q2", type: .trueFalse, questionText: "LLMs understand language the same way humans do.", options: ["True", "False"], correctAnswer: "False", explanation: "LLMs predict the most likely next token based on patterns. They do not truly understand meaning the way humans do, though the extent of their understanding is actively debated by researchers."),
        Question(id: "ga2_q3", type: .fillInBlank, questionText: "LLMs are trained on __________ amounts of text from the internet, books, and other sources.", options: ["massive", "curated", "moderate", "limited"], correctAnswer: "massive", explanation: "LLMs are trained on hundreds of billions of words from diverse text sources. The scale and quality of training data varies between models from Anthropic, Google DeepMind, Meta AI, and others."),
        Question(id: "ga2_q4", type: .multipleChoice, questionText: "How do LLMs generate text?", options: ["By predicting the most likely next token", "By searching a knowledge database in real-time", "By retrieving and combining stored sentences", "By following manually written grammar rules"], correctAnswer: "By predicting the most likely next token", explanation: "LLMs work by predicting the next token (word or subword) in a sequence, one at a time. This core mechanism is shared across Claude, GPT, Gemini, Llama, and Mistral."),
        Question(id: "ga2_q5", type: .matchPairs, questionText: "Match LLMs to their creators:", matchPairs: [
            MatchPair(term: "Claude", definition: "Anthropic"),
            MatchPair(term: "Gemini", definition: "Google DeepMind"),
            MatchPair(term: "Llama", definition: "Meta AI"),
            MatchPair(term: "Mistral", definition: "Mistral AI")
        ], explanation: "The LLM landscape includes both closed-source models (Claude, Gemini) and open-weight models (Llama, Mistral), each with different strengths and design philosophies."),
        Question(id: "ga2_q6", type: .multipleChoice, questionText: "What is a 'parameter' in an LLM?", options: ["A learned numerical value in the model", "A user-defined setting for outputs", "A rule manually written by developers", "A category of training data"], correctAnswer: "A learned numerical value in the model", explanation: "Parameters are the billions of numerical values that the model learns during training. Llama 3 has up to 405 billion parameters, while different model sizes offer trade-offs between capability and efficiency.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "ga_l3", title: "Transformers Architecture", description: "The technology behind modern AI", categoryId: "generative_ai", questions: [
        Question(id: "ga3_q1", type: .multipleChoice, questionText: "The Transformer architecture was introduced in a paper titled:", options: ["Attention Is All You Need", "The Future of Computing", "Neural Networks 101", "Deep Learning Basics"], correctAnswer: "Attention Is All You Need", explanation: "The landmark 2017 paper by Google researchers introduced the Transformer architecture that now powers virtually every major LLM, from Claude to Gemini to Llama."),
        Question(id: "ga3_q2", type: .trueFalse, questionText: "The attention mechanism helps models focus on relevant parts of the input.", options: ["True", "False"], correctAnswer: "True", explanation: "Self-attention allows the model to weigh the importance of different parts of the input when processing each token, enabling it to capture long-range dependencies in text."),
        Question(id: "ga3_q3", type: .fillInBlank, questionText: "The __________ mechanism is the key innovation in the Transformer architecture.", options: ["attention", "deletion", "compression", "copying"], correctAnswer: "attention", explanation: "Attention lets the model dynamically focus on the most relevant parts of the input sequence. Variants like multi-head attention and grouped-query attention are used in different models."),
        Question(id: "ga3_q4", type: .multipleChoice, questionText: "Why are Transformers better than previous models for language?", options: ["They can process entire sequences in parallel", "They require less training data overall", "They use simpler mathematical operations", "They process words strictly one at a time"], correctAnswer: "They can process entire sequences in parallel", explanation: "Unlike RNNs that processed words sequentially, Transformers process entire sequences at once, enabling much faster training and allowing models to scale to billions of parameters."),
        Question(id: "ga3_q5", type: .multipleChoice, questionText: "What does 'tokenization' mean in the context of LLMs?", options: ["Breaking text into smaller pieces for processing", "Converting text to numerical embeddings", "Assigning security permissions to data", "Grouping similar words by meaning"], correctAnswer: "Breaking text into smaller pieces for processing", explanation: "Tokenization splits text into tokens (words, subwords, or characters) that the model can process. Different models use different tokenizers, affecting how efficiently they handle various languages."),
        Question(id: "ga3_q6", type: .sortOrder, questionText: "Order the evolution of language AI:", options: ["Large Language Models", "Rule-based systems", "Transformer architecture", "Recurrent Neural Networks"], correctAnswers: ["Rule-based systems", "Recurrent Neural Networks", "Transformer architecture", "Large Language Models"], explanation: "Language AI evolved from simple rules to RNNs to Transformers, culminating in today's LLMs from Anthropic, Google DeepMind, Meta AI, OpenAI, and Mistral AI.")
    ], order: 2, difficulty: .advanced)
    static let lesson4 = LessonData(id: "ga_l4", title: "AI Hallucinations", description: "When AI makes things up", categoryId: "generative_ai", questions: [
        Question(id: "ga4_q1", type: .multipleChoice, questionText: "An 'AI hallucination' is when:", options: ["AI generates false information that sounds convincing", "AI sees visual hallucinations in images", "AI refuses to respond to a question", "AI runs out of memory mid-response"], correctAnswer: "AI generates false information that sounds convincing", explanation: "Hallucinations are fabricated outputs that sound plausible but are factually incorrect. All current LLMs — Claude, GPT, Gemini, Llama — can hallucinate."),
        Question(id: "ga4_q2", type: .trueFalse, questionText: "AI hallucinations are a solved problem in modern LLMs.", options: ["True", "False"], correctAnswer: "False", explanation: "Hallucinations remain one of the biggest unsolved challenges in AI. Every major lab, including Anthropic, Google DeepMind, and OpenAI, is actively researching ways to reduce them."),
        Question(id: "ga4_q3", type: .scenarioJudgment, questionText: "A lawyer uses an AI chatbot to find legal cases and cites them in court without verifying. The cases turn out to be fabricated. Who is at fault?", options: ["The lawyer", "Only the AI", "It depends"], correctAnswer: "The lawyer", explanation: "Professionals are responsible for verifying AI outputs. This happened in real life when a lawyer cited fabricated cases generated by an LLM and faced sanctions from the court."),
        Question(id: "ga4_q4", type: .fillInBlank, questionText: "You should always __________ important information generated by AI before relying on it.", options: ["verify", "ignore", "delete", "share"], correctAnswer: "verify", explanation: "Always fact-check AI outputs, especially for important decisions. This applies regardless of which model you use — Claude, Gemini, GPT, or any other LLM."),
        Question(id: "ga4_q5", type: .multipleChoice, questionText: "Why do LLMs hallucinate?", options: ["They predict likely text patterns, not verified facts", "Their training data only contains errors", "They lack sufficient computing power", "Their memory fills up during long conversations"], correctAnswer: "They predict likely text patterns, not verified facts", explanation: "LLMs generate statistically likely text, not verified facts. They do not have a database of truth to check against, which is why techniques like retrieval-augmented generation (RAG) are being developed."),
        Question(id: "ga4_q6", type: .multipleChoice, questionText: "Which strategy helps reduce the impact of AI hallucinations?", options: ["Cross-referencing with reliable sources", "Asking the AI if it is sure about its answer", "Assuming AI is always correct for efficiency", "Using older AI models instead of newer ones"], correctAnswer: "Cross-referencing with reliable sources", explanation: "The best defense against hallucinations is verifying AI outputs against trusted, authoritative sources. Some systems also use RAG to ground responses in retrieved documents.")
    ], order: 3, difficulty: .intermediate)
    static let lesson5 = LessonData(id: "ga_l5", title: "Image Generation AI", description: "Creating pictures with words", categoryId: "generative_ai", questions: [
        Question(id: "ga5_q1", type: .multipleChoice, questionText: "Image generation AI creates images from:", options: ["Text descriptions (prompts)", "Existing image databases only", "Pre-made templates only", "Pixel-by-pixel manual input"], correctAnswer: "Text descriptions (prompts)", explanation: "Text-to-image models like Stable Diffusion, DALL-E, and Midjourney generate images based on written descriptions, transforming how visual content is created."),
        Question(id: "ga5_q2", type: .trueFalse, questionText: "Diffusion models work by gradually removing noise from a random image.", options: ["True", "False"], correctAnswer: "True", explanation: "Diffusion models start with pure noise and gradually denoise it, guided by the text prompt, to create an image. Stability AI's Stable Diffusion popularized this approach as an open-source model."),
        Question(id: "ga5_q3", type: .matchPairs, questionText: "Match image AI tools to their key characteristics:", matchPairs: [
            MatchPair(term: "Stable Diffusion", definition: "Open-source, locally runnable"),
            MatchPair(term: "Midjourney", definition: "Known for artistic style"),
            MatchPair(term: "DALL-E", definition: "Integrated with ChatGPT"),
            MatchPair(term: "Firefly", definition: "Trained on licensed content")
        ], explanation: "Image generation spans open-source models anyone can run locally (Stable Diffusion) to commercial services (Midjourney, DALL-E), each with different approaches to training data and accessibility."),
        Question(id: "ga5_q4", type: .fillInBlank, questionText: "__________ models work by learning to remove noise from images step by step.", options: ["Diffusion", "Transformer", "Adversarial", "Classification"], correctAnswer: "Diffusion", explanation: "Diffusion models are trained to reverse a noise-adding process, gradually creating clear images from random noise. This technique powers Stable Diffusion, DALL-E 3, and many other image generators."),
        Question(id: "ga5_q5", type: .scenarioJudgment, questionText: "An artist discovers their style has been replicated by an AI image generator trained on their work without permission. Is this ethical?", options: ["No, it's problematic", "Yes, it's fine", "It depends"], correctAnswer: "No, it's problematic", explanation: "Using artists' work to train AI without consent raises serious ethical and copyright concerns. This debate has led to lawsuits against Stability AI, Midjourney, and others, and some companies now use only licensed training data."),
        Question(id: "ga5_q6", type: .multipleChoice, questionText: "What can current image AI NOT do well?", options: ["Consistently generate correct text in images", "Create photorealistic landscapes", "Generate realistic human faces", "Produce abstract and stylized art"], correctAnswer: "Consistently generate correct text in images", explanation: "Image AI often struggles with rendering text correctly, producing misspelled or garbled words. This is because these models process visual patterns rather than understanding language structure.")
    ], order: 4, difficulty: .intermediate)
    static let lesson6 = LessonData(id: "ga_l6", title: "Responsible Use of Generative AI", description: "Ethics and best practices", categoryId: "generative_ai", questions: [
        Question(id: "ga6_q1", type: .multipleChoice, questionText: "When using generative AI for work, you should:", options: ["Always disclose AI use and review outputs", "Use it without telling clients or colleagues", "Rely on it for final decisions without review", "Only use it for tasks where errors don't matter"], correctAnswer: "Always disclose AI use and review outputs", explanation: "Transparency about AI use and verifying outputs are key principles of responsible generative AI usage, emphasized by Anthropic's usage policies and the EU AI Act."),
        Question(id: "ga6_q2", type: .trueFalse, questionText: "It's generally safe to input confidential business data into public AI chatbots.", options: ["True", "False"], correctAnswer: "False", explanation: "Public AI services may retain or use inputs for training. Confidential data should only be shared with AI tools that have appropriate enterprise privacy agreements, such as dedicated API access or on-premise deployments."),
        Question(id: "ga6_q3", type: .scenarioJudgment, questionText: "A company creates AI-generated marketing images featuring diverse people who do not exist. Should they disclose this?", options: ["Yes, disclose it", "No, no need", "It depends"], correctAnswer: "Yes, disclose it", explanation: "Using AI-generated people in marketing should be disclosed to maintain trust and avoid misleading consumers. Many jurisdictions are introducing regulations requiring AI content labeling."),
        Question(id: "ga6_q4", type: .fillInBlank, questionText: "The concept of keeping humans involved in AI decision-making is called 'human in the __________.'", options: ["loop", "cloud", "server", "code"], correctAnswer: "loop", explanation: "Human-in-the-loop means keeping humans involved in reviewing and making final decisions on AI outputs. This is a core safety principle advocated by Anthropic, Google DeepMind, and AI regulators worldwide."),
        Question(id: "ga6_q5", type: .multipleChoice, questionText: "What is the best practice when AI-generated content will be published?", options: ["Review, edit, and fact-check before publishing", "Publish immediately without review", "Add a disclaimer that you did not read it", "Only publish if the AI says it is accurate"], correctAnswer: "Review, edit, and fact-check before publishing", explanation: "AI outputs should always be reviewed by a human for accuracy, tone, and appropriateness before publication, regardless of whether the content came from Claude, Gemini, GPT, or any other model."),
        Question(id: "ga6_q6", type: .multipleChoice, questionText: "Which is a key concern about generative AI and misinformation?", options: ["AI can create convincing fake content at scale", "AI always produces truthful content", "AI-generated content is easy to identify", "AI cannot create realistic fake content"], correctAnswer: "AI can create convincing fake content at scale", explanation: "Generative AI makes it easy to create realistic fake text, images, audio, and videos (deepfakes), raising concerns about misinformation. This is why AI safety research and content provenance standards are critical priorities.")
    ], order: 5, difficulty: .intermediate)
}
